void solve(int CASE)
{
	var a = vector<pair<int, char>>(3);
	fa(i, 0, 2)cin >> a[i].px;
	a[0].py = 'R', a[1].py = 'G', a[2].py = 'B';
	sort(all(a), greater<>());

	bool tail = 0;
	if (a[0].px > a[1].px + a[2].px) a[0].px = a[1].px + a[2].px, tail = 1;
	int y = a[0].px - a[1].px, x = a[0].px - a[2].px, z = a[2].px + a[1].px - a[0].px;

	string ans;
	bool ac = 0;
	while (x--) {
		string tmp = { a[0].py, a[1].py };
		ans.insert(ans.end(), all(tmp));
	}
	while (y--) {
		string tmp = { a[0].py, a[2].py };
		ans.insert(ans.end(), all(tmp));
	}

	if (tail)ans.pb(a[0].py); // 如果带多余的 A
	else {
		// 全排列找合适的 ABC 序列
		vector<string> tmp;
		string tmp0 = "BGR";
		do {
			bool ok = 1;
			fa(i, 0, 2) {
				int j = vs(ans) + i - 2;
				if (j >= 0 and tmp0[i] == ans[j]) {
					ok = 0;
					break;
				}
			}
			if (ans.size() and ans.back() == tmp0[0])ok = 0;
			if (ok) {
				tmp.pb(tmp0);
				rotate(tmp0.begin(), tmp0.begin() + 1, tmp0.end());
				tmp.pb(tmp0);
				rotate(tmp0.begin(), tmp0.begin() + 1, tmp0.end());
				tmp.pb(tmp0);
				break;
			}
		} while (next_permutation(all(tmp0)));

		int now = 0;
		while (z--) {
			ans.insert(ans.end(), all(tmp[now]));
			now = (now + 1) % 3;
		}
	}
	cout << ans << endl;
	return;
}
